            contentType: "application/json",
            dataType: 'json',
            callbackParameter: "c",
            cache: true,
            headers: {'Cache-Control': 'max-age=10'},
            success: function (data) {
                let count = 0;
                $.each(data.latest_notification_count, function( key, value ) {
                    if (value == cookieData) {
                        return false;
                    } else {
                        return count++;
                    }
                });
                data.latest_count_bell = count;
                if (cookieData != '') {
                    setNewsCount(data);             
                } else {
